<div class="tc-joy" x-data="joyWidget()" @keydown.escape.window="close()">
<button x-ref="launcher" class="tc-joy-launcher" @click="toggle()" :aria-expanded="open.toString()" aria-controls="joy-panel" aria-label="Open Joy assistant"><img src="{{ asset('img/joy-avatar.svg') }}" alt="" width="34" height="34"></button>
<section id="joy-panel" class="tc-joy-panel" x-cloak x-show="open" aria-label="Joy assistant"><header class="tc-joy-header"><strong>Joy</strong><button class="btn btn-sm" @click="close()" aria-label="Close"><i class="bi bi-x-lg"></i></button></header><div class="tc-joy-messages" x-ref="scroll" aria-live="polite"><p x-show="messages.length===0" class="text-center text-body-secondary py-4">Hi, I'm Joy! How can I help?</p><template x-for="(m,i) in messages" :key="i"><div><p class="text-end"><span class="p-2 rounded bg-primary text-white" x-text="m.question"></span></p><p><span class="p-2 rounded bg-body-secondary" x-text="m.reply"></span></p></div></template><span x-show="awaiting" class="spinner-border spinner-border-sm"></span></div><form class="tc-joy-form" @submit.prevent="send()"><input x-ref="input" class="form-control" x-model="draft" maxlength="1000" placeholder="Message Joy..." :disabled="awaiting"><button class="btn btn-primary" :disabled="awaiting||!draft.trim()" aria-label="Send"><i class="bi bi-send"></i></button></form></section></div>
@push('scripts')<script>document.addEventListener('alpine:init',()=>Alpine.data('joyWidget',()=>({open:false,messages:[],draft:'',awaiting:false,toggle(){this.open?this.close():(this.open=true,this.$nextTick(()=>this.$refs.input.focus()))},close(){this.open=false;this.$nextTick(()=>this.$refs.launcher.focus())},async send(){const q=this.draft.trim();if(!q||this.awaiting)return;this.draft='';this.awaiting=true;try{const r=await fetch('{{ route('portal.chatbot.message') }}',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content,'Accept':'application/json'},body:JSON.stringify({message:q})});const b=await r.json();if(!r.ok)throw 0;this.messages.push({question:q,reply:b.answer?.reply||b.data?.reply||"I'm not sure how to help with that yet."})}catch(e){this.messages.push({question:q,reply:"Sorry, I couldn't reply just now. Please try again."})}finally{this.awaiting=false;this.$nextTick(()=>this.$refs.scroll.scrollTop=this.$refs.scroll.scrollHeight)}}})))</script>@endpush
